@main_bp.route("/admin")
def admin_route():
    """
    Route pour afficher la page admin.
    """
    try:
        print("[DEBUG] Accès à la page admin.")
        data = admin()
        return render_template(f"{data['active_theme']}/admin.html", data=data)
    except Exception as e:
        print(f"[ERREUR] Une erreur est survenue lors du rendu de la page admin : {e}")
        print(f"[DEBUG] Traceback : {traceback.format_exc()}")
        return "Erreur interne", 500

